#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    // Calculate prefix XOR array
    vector<long long> prefix_xor(nums.size() + 1, 0);
    for (int i = 0; i < nums.size(); ++i) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    // The minimum possible maximum XOR is 0, and the maximum possible is the XOR of the entire array
    long long left = 0, right = prefix_xor.back();
    long long answer = right;

    // Binary search on the possible XOR values
    while (left <= right) {
        long long mid = (left + right) / 2;
        int count = 1; // At least one subarray
        long long prev_xor = 0;

        // Check if it's possible to split the array into k subarrays such that the maximum XOR is <= mid
        for (int i = 1; i <= nums.size(); ++i) {
            if (prefix_xor[i] ^ prev_xor > mid) {
                // Need to split here
                count++;
                prev_xor = prefix_xor[i];
            }
        }

        // If we can split into k or fewer subarrays, try to find a smaller maximum XOR
        if (count <= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}
